def.body:
if @done
  return
end

while line = @lines.next_line
  if fasta_header?(line)
    @set_pending_name.call(String.new(line[1, line.size - 1]))
    @done = true
    return
  end

  validate_ascii_line!(line)
  yield line
end

@done = true

@io.write_byte(62_u8)
@io.write(name)
@io.write_byte(10_u8)

line_width = @line_width
if line_width
  start = 0
  while start < sequence.size
    chunk_size = Math.min(line_width, sequence.size - start)
    @io.write(sequence[start, chunk_size])
    @io.write_byte(10_u8)
    start = start + chunk_size
  end
else
  @io.write(sequence)
  @io.write_byte(10_u8)
end

if sequence.size == quality.size
else
  raise(ArgumentError.new("sequence and quality lengths differ"))
end

@io.write_byte(64_u8)
@io.write(identifier)
@io.write_byte(10_u8)
@io.write(sequence)
@io.write_byte(10_u8)
@io.write_byte(43_u8)
@io.write_byte(10_u8)
@io.write(quality)
@io.write_byte(10_u8)
